// Compute days-until-due and the 90/60/30/7-day reminder tier.
// Mirrors src/lib/schedules.ts so the n8n workflow and the in-app engine agree.
const TIERS = [90, 60, 30, 7];
const out = [];
for (const item of $input.all()) {
  const r = item.json;
  if (!r.expiration_date) continue;
  const today = new Date();
  today.setUTCHours(0, 0, 0, 0);
  const due = new Date(r.expiration_date.length <= 10 ? r.expiration_date + 'T00:00:00Z' : r.expiration_date);
  due.setUTCHours(0, 0, 0, 0);
  const daysUntilDue = Math.round((due.getTime() - today.getTime()) / 86400000);
  // Fire only on the exact threshold days (matches scheduled-reminders behaviour).
  if (!TIERS.includes(daysUntilDue)) continue;
  const tier = daysUntilDue + '-day';
  const ceuRemaining = Math.max(0, Number(r.ceu_total_required || 0) - Number(r.ceu_total_approved || 0));
  out.push({ json: { ...r, daysUntilDue, tier, ceuRemaining } });
}
return out;
